15	package org.apache.tapestry5.internal.services;
16	
17	import org.apache.tapestry5.SymbolConstants;
18	import org.apache.tapestry5.alerts.AlertManager;
19	import org.apache.tapestry5.internal.InternalConstants;
20	import org.apache.tapestry5.internal.TapestryInternalUtils;
21	import org.apache.tapestry5.internal.util.Base64InputStream;
22	import org.apache.tapestry5.internal.util.MacOutputStream;
23	import org.apache.tapestry5.ioc.annotations.Symbol;
24	import org.apache.tapestry5.services.ClientDataEncoder;
25	import org.apache.tapestry5.services.ClientDataSink;
26	import org.apache.tapestry5.services.URLEncoder;
27	import org.slf4j.Logger;
28	
29	import javax.crypto.spec.SecretKeySpec;
30	import java.io.BufferedInputStream;
31	import java.io.IOException;
32	import java.io.ObjectInputStream;
33	import java.io.UnsupportedEncodingException;
34	import java.security.Key;
35	import java.util.zip.GZIPInputStream;
36	
37	public class ClientDataEncoderImpl implements ClientDataEncoder
38	{
39	    private final URLEncoder urlEncoder;
40	
41	    private final Key hmacKey;
42	
43	    public ClientDataEncoderImpl(URLEncoder urlEncoder, @Symbol(SymbolConstants.HMAC_PASSPHRASE) String passphrase,
44	                                 Logger logger,
45	                                 @Symbol(InternalConstants.TAPESTRY_APP_PACKAGE_PARAM)
46	                                 String applicationPackageName, AlertManager alertManager) throws UnsupportedEncodingException
47	    {
48	        this.urlEncoder = urlEncoder;
49	
50	        if (passphrase.equals(""))
51	        {
52	            String message = String.format("The symbol '%s' has not been configured. " +
53	                    "This is used to configure hash-based message authentication of Tapestry data stored in forms, or in the URL. " +
54	                    "You application is less secure, and more vulnerable to denial-of-service attacks, when this symbol is not configured.",
55	                    SymbolConstants.HMAC_PASSPHRASE);
56	
57	            // Now to really get the attention of the developer!
58	
59	            alertManager.error(message);
60	
61	            logger.error(message);
62	
63	            // Override the blank parameter to set a default value. Use the application package name,
64	            // which is justly slightly more secure than having a fixed default.
65	            passphrase = applicationPackageName;
66	        }
67	
68	        hmacKey = new SecretKeySpec(passphrase.getBytes("UTF8"), "HmacSHA1");
69	    }
70	
71	    public ClientDataSink createSink()
72	    {
73	        try
74	        {
75	            return new ClientDataSinkImpl(urlEncoder, hmacKey);
76	        } catch (IOException ex)
77	        {
78	            throw new RuntimeException(ex);
79	        }
80	    }
81	
82	    public ObjectInputStream decodeClientData(String clientData)
83	    {
84	        // The clientData is Base64 that's been gzip'ed (i.e., this matches
85	        // what ClientDataSinkImpl does).
86	
87	        int colonx = clientData.indexOf(':');
88	
89	        if (colonx < 0)
90	        {
91	            throw new IllegalArgumentException("Client data must be prefixed with its HMAC code.");
92	        }
93	
94	        // Extract the string presumably encoded by the server using the secret key.
95	
96	        String storedHmacResult = clientData.substring(0, colonx);
97	
98	        String clientStream = clientData.substring(colonx + 1);
99	
100	        try
101	        {
102	            Base64InputStream b64in = new Base64InputStream(clientStream);
103	
104	            validateHMAC(storedHmacResult, b64in);
105	
106	            // After reading it once to validate, reset it for the actual read (which includes the GZip decompression).
107	
108	            b64in.reset();
109	
110	            BufferedInputStream buffered = new BufferedInputStream(new GZIPInputStream(b64in));
111	
112	            return new ObjectInputStream(buffered);
113	        } catch (IOException ex)
114	        {
115	            throw new RuntimeException(ex);
116	        }
117	    }
118	
119	    private void validateHMAC(String storedHmacResult, Base64InputStream b64in) throws IOException
120	    {
121	        MacOutputStream macOs = MacOutputStream.streamFor(hmacKey);
122	
123	        TapestryInternalUtils.copy(b64in, macOs);
124	
125	        macOs.close();
126	
127	        String actual = macOs.getResult();
128	
129	        if (!storedHmacResult.equals(actual))
130	        {
131	            throw new IOException("Client data associated with the current request appears to have been tampered with " +
132	                    "(the HMAC signature does not match).");
133	        }
134	    }
135	
136	    public ObjectInputStream decodeEncodedClientData(String clientData) throws IOException
137	    {
138	        return decodeClientData(urlEncoder.decode(clientData));
139	    }
140	}
