15	package org.apache.tapestry5.ioc.internal;
16	
17	import org.slf4j.Logger;
18	import org.slf4j.LoggerFactory;
19	
20	import java.lang.ref.WeakReference;
21	
22	/**
23	 * Serialization support for service proxies.
24	 */
25	class SerializationSupport
26	{
27	    private static final Logger LOGGER = LoggerFactory.getLogger(SerializationSupport.class);
28	
29	    // We use a weak reference so that the underlying Registry can be reclaimed by the garbage collector
30	    // even if it is not explicitly shut down.
31	
32	    private static WeakReference<ServiceProxyProvider> providerRef;
33	
34	    static synchronized void setProvider(ServiceProxyProvider proxyProvider)
35	    {
36	        ServiceProxyProvider existing = currentProvider();
37	
38	        if (existing != null) LOGGER.error(IOCMessages.overlappingServiceProxyProviders());
39	
40	        providerRef = new WeakReference<ServiceProxyProvider>(proxyProvider);
41	    }
42	
43	    // Only invoked from synchronized blocks
44	    private static ServiceProxyProvider currentProvider()
45	    {
46	        return providerRef == null ? null : providerRef.get();
47	    }
48	
49	    static synchronized void clearProvider(ServiceProxyProvider proxyProvider)
50	    {
51	        ServiceProxyProvider existing = currentProvider();
52	
53	        // The registry does a setProvider() at startup, and we want to make sure that we're the only Registry, that
54	        // there hasn't been another setProvider() by another Registry.
55	
56	        if (existing != proxyProvider)
57	        {
58	            LOGGER.error(IOCMessages.unexpectedServiceProxyProvider());
59	            return;
60	        }
61	
62	        // Good. It's all the expected simple case, without duelling registries. Kill the reference
63	        // to the registry.
64	
65	        providerRef = null;
66	    }
67	
68	    static synchronized Object readResolve(String serviceId)
69	    {
70	        ServiceProxyProvider provider = currentProvider();
71	
72	        if (provider == null) throw new RuntimeException(IOCMessages.noProxyProvider(serviceId));
73	
74	        return provider.provideServiceProxy(serviceId);
75	    }
76	
77	    static ServiceProxyToken createToken(String serviceId)
78	    {
79	        return new ServiceProxyToken(serviceId);
80	    }
81	
82	}
