24	/**
25	 * Basic implementation of {@link org.apache.tapestry5.services.Request} that wraps around an
26	 * {@link javax.servlet.http.HttpServletRequest}. This is not threadsafe, nor should it need to be (each Request is
27	 * handled by its own Thread).
28	 */
29	public class RequestImpl implements Request
30	{
31	    static final String REQUESTED_WITH_HEADER = "X-Requested-With";
32	
33	    static final String XML_HTTP_REQUEST = "XMLHttpRequest";
34	
35	    static final String X_FORWARDED_PROTO_HEADER = "X-Forwarded-Proto";
36	    static final String X_FORWARDED_PROTO_HTTPS = "https";
37	
38	    private final HttpServletRequest request;
39	
40	    private final String applicationCharset;
41	
42	    private final TapestrySessionFactory sessionFactory;
43	
