34	    private transient AtomicBoolean dirty = new AtomicBoolean(false);
35	
36	    private void readObject(java.io.ObjectInputStream in) throws IOException, ClassNotFoundException {
37	        dirty = new AtomicBoolean(false);
38	    }
39	
40	    public final boolean checkAndResetDirtyMarker()
41	    {
42	        return dirty.getAndSet(false);
43	    }
44	
45	    /**
46	     * Invoked by the subclass after internal state of the object changes.
47	     */
48	    protected final void markDirty()
49	    {
50	        dirty.set(true);
