93	    private PropertyWriter newPropertyWriter(final PrintWriter writer, Iterable<String> names)
94	    {
95	        final int maxPropertyNameLength = F.flow(names).map(STRING_TO_LENGTH).reduce(MAX, 0);
96	
97	        final String propertyNameFormat = "  %" + maxPropertyNameLength + "s: %s%n";
98	
99	        return new PropertyWriter()
100	        {
101	            @SuppressWarnings("rawtypes")
102	            @Override
103	            public void write(String name, Object value)
104	            {
105	                if (value.getClass().isArray())
106	                {
107	                    write(name, toList(value));
108	                    return;
109	                }
110	
111	                if (value instanceof Iterable)
112	                {
113	                    boolean first = true;
114	                    Iterable iterable = (Iterable) value;
115	                    Iterator i = iterable.iterator();
116	                    while (i.hasNext())
117	                    {
118	                        if (first)
119	                        {
120	                            writer.printf(propertyNameFormat, name, i.next());
121	                            first = false;
122	                        } else
123	                        {
124	                            for (int j = 0; j < maxPropertyNameLength + 4; j++)
125	                                writer.write(' ');
126	
127	                            writer.println(i.next());
128	                        }
129	                    }
130	                    return;
131	                }
132	
133	                writer.printf(propertyNameFormat, name, value);
134	            }
